#include <time.h>

void reservoir_sample(const int *stream, int n, int *reservoir, int k) {
  if (k <= 0 || n <= 0) return;
  for (int i = 0; i < k && i < n; i++) {
    reservoir[i] = stream[i];
  }
  if (n <= k) return;
  for (int i = k; i < n; i++) {
    int j = rand() % (i + 1);
    if (j < k) {
      reservoir[j] = stream[i];
    }
  }
}

