func ReservoirSample(stream []int, k int) []int {
	if k <= 0 {
		return []int{}
	}
	if len(stream) <= k {
		out := make([]int, len(stream))
		copy(out, stream)
		return out
	}
	reservoir := make([]int, k)
	copy(reservoir, stream[:k])
	r := rand.New(rand.NewSource(time.Now().UnixNano()))
	for i := k; i < len(stream); i++ {
		j := r.Intn(i + 1)
		if j < k {
			reservoir[j] = stream[i]
		}
	}
	return reservoir
}

