sub reservoir_sample {
  my ($stream, $k) = @_;
  return () if $k <= 0;
  return @$stream if scalar(@$stream) <= $k;
  my @reservoir = @{$stream}[0..($k - 1)];
  for my $i ($k .. (scalar(@$stream) - 1)) {
    my $j = int(rand($i + 1));
    if ($j < $k) {
      $reservoir[$j] = $stream->[$i];
    }
  }
  return @reservoir;
}

